import { useSourceName } from "@/features/sources/hooks/useSourceName";
import { useLocalizedTagLabels } from "@/features/tags/hooks/useLocalizedTagLabels";
import type { RecipeMetadata } from "@/lib/types/recipe";
import { LinearGradient } from "expo-linear-gradient";
import { type JSX } from "react";
import { Pressable, StyleSheet, Text, View } from "react-native";

export function MetadataOverlay({
  metadata,
  onPress,
  disabled,
}: {
  metadata: RecipeMetadata;
  onPress?: () => void;
  disabled?: boolean;
}): JSX.Element | null {
  const { displayName: sourceDisplayName } = useSourceName(metadata.source);
  const tagLabels = useLocalizedTagLabels(metadata.tagIds);
  const hasTitle = !!metadata.title;
  const hasSource = !!sourceDisplayName;
  const hasTags = tagLabels.length > 0;

  if (!hasTitle && !hasSource && !hasTags) {
    return null;
  }

  return (
    <LinearGradient
      colors={["rgba(0,0,0, 1)", "rgba(0,0,0,0.6)", "transparent"]}
      locations={[0, 0.6, 1]}
      style={styles.gradient}
      pointerEvents="box-none"
    >
      <Pressable
        onPress={onPress}
        disabled={disabled || !onPress}
        style={({ pressed }) => [
          styles.pressable,
          { opacity: pressed ? 0.7 : 1 },
        ]}
        hitSlop={8}
      >
        {hasTitle && (
          <Text style={styles.title} numberOfLines={2} ellipsizeMode="tail">
            {metadata.title}
          </Text>
        )}
        {hasSource && (
          <Text style={styles.source} numberOfLines={1} ellipsizeMode="tail">
            {sourceDisplayName}
          </Text>
        )}
        {hasTags && (
          <View style={styles.tagsContainer}>
            <Text style={styles.tags} numberOfLines={1} ellipsizeMode="tail">
              {tagLabels.join("  ")}
            </Text>
          </View>
        )}
      </Pressable>
    </LinearGradient>
  );
}

const styles = StyleSheet.create({
  gradient: {
    position: "absolute",
    top: 0,
    left: 0,
    right: 0,
    paddingHorizontal: 16,
    paddingTop: 80,
    paddingBottom: 80,
  },
  title: {
    color: "white",
    fontSize: 24,
    fontWeight: "bold",
    textShadowColor: "rgba(0, 0, 0, 0.8)",
    textShadowOffset: { width: 0, height: 1 },
    textShadowRadius: 3,
    marginBottom: 4,
  },
  source: {
    color: "white",
    fontSize: 14,
    fontStyle: "italic",
    textShadowColor: "rgba(0, 0, 0, 0.8)",
    textShadowOffset: { width: 0, height: 1 },
    textShadowRadius: 3,
    marginBottom: 8,
  },
  tagsContainer: {
    flexDirection: "row",
  },
  tags: {
    color: "white",
    fontSize: 14,
    textShadowColor: "rgba(0, 0, 0, 0.8)",
    textShadowOffset: { width: 0, height: 1 },
    textShadowRadius: 3,
  },
});

import { DebugVisualization } from "@/features/photo-adjustment/components/DebugVisualization";
import { useDebugContext } from "@/features/photo-adjustment/context/DebugContext";
import { useRecipes } from "@/features/recipes-list/context/RecipesContext";
import { Alert } from "@/lib/alert";
import { BackButton } from "@/lib/components/atoms/BackButton";
import { DeleteButton } from "@/lib/components/atoms/DeleteButton";
import { EditButton } from "@/lib/components/atoms/EditButton";
import { ProgressiveImage } from "@/lib/components/atoms/ProgressiveImage";
import { ZoomableImage } from "@/lib/components/atoms/ZoomableImage";
import { useImageCoverSize } from "@/lib/hooks/useImageCoverSize";
import type { RecipeId } from "@/lib/types/primitives";
import { useTranslation } from "@/platform/i18n/useTranslation";
import { useRouter } from "expo-router";
import { type JSX, useCallback, useEffect, useState } from "react";

import { StyleSheet, useWindowDimensions, View } from "react-native";
import type { SwipeDirection } from "react-native-zoom-toolkit";
import Animated, {
  useAnimatedStyle,
  withTiming,
} from "react-native-reanimated";
import { useRecipeById } from "../hooks/useRecipeById";
import { MetadataOverlay } from "./MetadataOverlay";
import { ProcessingIndicator } from "./ProcessingIndicator";

export function RecipeViewScreen({ id }: { id: RecipeId }): JSX.Element | null {
  const recipe = useRecipeById(id);
  const router = useRouter();
  const { t } = useTranslation();
  const { setDebugData } = useDebugContext();
  const { deleteRecipe } = useRecipes();

  useEffect(() => {
    return () => {
      setDebugData(null);
    };
  }, [setDebugData]);

  const handleEdit = useCallback((): void => {
    router.push(`/recipe/${id}/edit`);
  }, [router, id]);

  const handleBack = useCallback((): void => {
    router.back();
  }, [router]);

  const handleSwipe = useCallback(
    (direction: SwipeDirection): void => {
      if (direction === "right") {
        router.back();
      }
    },
    [router]
  );

  const handleDelete = useCallback((): void => {
    Alert.alert(t("deleteRecipe.title"), t("deleteRecipe.message"), [
      {
        text: t("deleteRecipe.cancel"),
        style: "cancel",
      },
      {
        text: t("deleteRecipe.confirm"),
        style: "destructive",
        onPress: async () => {
          await deleteRecipe(id);
          router.replace("/");
        },
      },
    ]);
  }, [t, deleteRecipe, id, router]);

  const [isZoomed, setIsZoomed] = useState(false);
  const { width, height } = useWindowDimensions();
  const { coverSize, onImageLoad } = useImageCoverSize(width, height);

  const overlayStyle = useAnimatedStyle(() => ({
    opacity: withTiming(isZoomed ? 0 : 1, { duration: 200 }),
  }));

  if (!recipe) {
    return null;
  }

  const isProcessing =
    recipe.status === "pending" || recipe.status === "processing";
  const isReady = recipe.status === "ready";

  return (
    <View style={styles.container}>
      <ZoomableImage
        style={{ width, height }}
        onZoomChange={setIsZoomed}
        onSwipe={handleSwipe}
      >
        <ProgressiveImage
          uri={recipe.photoUri}
          thumbnailUri={recipe.thumbnailUri}
          style={coverSize ?? { width, height }}
          onLoad={onImageLoad}
        />
      </ZoomableImage>
      <Animated.View
        style={[styles.overlay, overlayStyle]}
        pointerEvents={isZoomed ? "none" : "box-none"}
      >
        <View pointerEvents="none" style={StyleSheet.absoluteFillObject}>
          <MetadataOverlay metadata={recipe.metadata} />
          {isProcessing && <ProcessingIndicator />}
          <DebugVisualization />
        </View>
        <BackButton onPress={handleBack} />
        <DeleteButton onPress={handleDelete} />
        <EditButton onPress={handleEdit} disabled={!isReady} />
      </Animated.View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: "#000000",
  },
  overlay: {
    ...StyleSheet.absoluteFillObject,
  },
});

